listitem.programlisting:
#!/bin/bash
CMD=${1:-start} case ${CMD} in genkeys) MODE="-ti --rm" EXEC="/usr/bin/server -g" ;; start) MODE="-d --restart=unless-stopped" EXEC="" ;; stop) docker stop katzenpost-mix docker rm katzenpost-mix exit ;; *) echo "unknown command" exit 1 ;; esac
docker run ${MODE} \ --name katzenpost-mix -h katzenpost-mix \ -p 0.0.0.0:<port>:8181 \ -v $(pwd)/conf:/conf \ -v $(pwd)/data:/var/lib/katzenpost \ katzenpost/mix ${EXEC}
